import{_ as a,o as n,c as e,ae as r}from"./chunks/framework.Co1PSFSm.js";const c=JSON.parse('{"title":"Agent 执行器架构分析","description":"","frontmatter":{},"headers":[],"relativePath":"agent-runner.md","filePath":"agent-runner.md"}'),s={name:"agent-runner.md"};function d(o,t,l,i,p,h){return n(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="agent-执行器架构分析" tabindex="-1">Agent 执行器架构分析 <a class="header-anchor" href="#agent-执行器架构分析" aria-label="Permalink to &quot;Agent 执行器架构分析&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>Agent 执行器（Agent Runner）是 AstrBot v4.7.0 引入的核心架构抽象，负责&quot;思考 + 做事&quot;，与只负责&quot;说话&quot;的 Chat Provider 形成职责分离。AstrBot 目前支持五种执行器：内置、Dify、Coze、阿里云百炼、DeerFlow。</p><h2 id="核心设计问题" tabindex="-1">核心设计问题 <a class="header-anchor" href="#核心设计问题" aria-label="Permalink to &quot;核心设计问题&quot;">​</a></h2><h3 id="为什么不把-dify-coze-百炼当作普通-chat-provider" tabindex="-1">为什么不把 Dify/Coze/百炼当作普通 Chat Provider？ <a class="header-anchor" href="#为什么不把-dify-coze-百炼当作普通-chat-provider" aria-label="Permalink to &quot;为什么不把 Dify/Coze/百炼当作普通 Chat Provider？&quot;">​</a></h3><p>早期这些平台作为普通 Chat Provider 集成，但它们自带 Agent 能力，与传统&quot;单轮文本补全&quot; Provider 有本质差异：</p><table tabindex="0"><thead><tr><th>维度</th><th>Chat Provider</th><th>Agent Runner</th></tr></thead><tbody><tr><td>输入</td><td>prompt + 历史 + 工具列表</td><td>用户意图 + 上下文 + 环境状态</td></tr><tr><td>输出</td><td>文本 / 工具调用</td><td>多轮循环：感知→规划→执行→观察→再规划</td></tr><tr><td>本质</td><td>单轮补全接口</td><td>策略驱动的动作循环</td></tr><tr><td>代表</td><td>OpenAI、Claude</td><td>Dify、Coze、百炼应用</td></tr></tbody></table><p>强行将 Agent Runner 当作 Chat Provider 会导致功能冲突：外部平台已在内部实现了 Agent 循环，若再套一层 AstrBot 内置执行器，会产生双重循环问题。</p><h2 id="架构分层" tabindex="-1">架构分层 <a class="header-anchor" href="#架构分层" aria-label="Permalink to &quot;架构分层&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                  AstrBot 上层应用                     │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  Agent Runner（思考 + 做事）                          │</span></span>
<span class="line"><span>│  ┌─────────┬─────────┬─────────┬─────────┬────────┐ │</span></span>
<span class="line"><span>│  │ 内置Runner │ Dify   │ Coze    │ 百炼    │ DeerFlow│ │</span></span>
<span class="line"><span>│  └────┬────┴────┬────┴────┬────┴────┬────┴────┬────┘ │</span></span>
<span class="line"><span>│       └──────────────┬──────────────────────────┘    │</span></span>
<span class="line"><span>│                      ▼                               │</span></span>
<span class="line"><span>│  Chat Provider（说话：文本补全）                       │</span></span>
<span class="line"><span>│  ┌─────────┬─────────┬─────────┬─────────┐         │</span></span>
<span class="line"><span>│  │OpenAI  │ Claude  │ Dify    │ 百炼    │ ...    │</span></span>
<span class="line"><span>│  └─────────┴─────────┴─────────┴─────────┘         │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────┘</span></span></code></pre></div><h2 id="agent-runner-执行循环" tabindex="-1">Agent Runner 执行循环 <a class="header-anchor" href="#agent-runner-执行循环" aria-label="Permalink to &quot;Agent Runner 执行循环&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户意图 → 感知(Observe) → 规划(Plan) → 执行(Act) → 观察(Observe) → ... → 结束</span></span></code></pre></div><ol><li><strong>感知（Observe）</strong>：读取环境状态、工具返回结果、对话历史</li><li><strong>规划（Plan）</strong>：基于策略/模型决定下一步动作</li><li><strong>执行（Act）</strong>：调用工具、操作环境</li><li><strong>循环</strong>：重复直到任务完成或超时</li></ol><h2 id="内置执行器能力" tabindex="-1">内置执行器能力 <a class="header-anchor" href="#内置执行器能力" aria-label="Permalink to &quot;内置执行器能力&quot;">​</a></h2><p>内置执行器配合 AstrBot 生态可实现：</p><ul><li><strong>MCP 集成</strong>：通过 MCP 协议调用外部工具</li><li><strong>知识库</strong>：向量检索增强回答</li><li><strong>网页搜索</strong>：实时信息获取</li><li><strong>代码执行</strong>：Local（风险）或 Sandbox（隔离）环境</li></ul><h2 id="执行环境" tabindex="-1">执行环境 <a class="header-anchor" href="#执行环境" aria-label="Permalink to &quot;执行环境&quot;">​</a></h2><table tabindex="0"><thead><tr><th>环境</th><th>说明</th><th>风险</th></tr></thead><tbody><tr><td>Local</td><td>Agent 在 AstrBot 运行环境中执行</td><td>高风险：任意代码执行权限</td></tr><tr><td>Sandbox</td><td>隔离沙盒环境</td><td>低风险：权限受限</td></tr></tbody></table><p>Local 模式下仅管理员请求可真正执行，普通用户会被拒绝。</p><h2 id="runner-类型一览" tabindex="-1">Runner 类型一览 <a class="header-anchor" href="#runner-类型一览" aria-label="Permalink to &quot;Runner 类型一览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Runner</th><th>来源</th><th>特点</th></tr></thead><tbody><tr><td>内置 Runner</td><td>AstrBot 原生</td><td>配合 MCP/知识库/搜索</td></tr><tr><td>Dify Runner</td><td>Dify 平台</td><td>Dify 内置 Agent 循环</td></tr><tr><td>Coze Runner</td><td>Coze 平台</td><td>Coze 内置 Agent 循环</td></tr><tr><td>百炼 Runner</td><td>阿里云百炼</td><td>百炼应用内置 Agent 循环</td></tr><tr><td>DeerFlow Runner</td><td>DeerFlow</td><td>DeerFlow 内置 Agent 循环</td></tr></tbody></table><h2 id="设计价值" tabindex="-1">设计价值 <a class="header-anchor" href="#设计价值" aria-label="Permalink to &quot;设计价值&quot;">​</a></h2><ul><li><strong>职责清晰</strong>：Provider 管补全，Runner 管执行</li><li><strong>扩展灵活</strong>：新增 Runner 只需实现接口，无需改动核心</li><li><strong>生态兼容</strong>：内置 Runner 享有 MCP、知识库等 AstrBot 特有能力；外部 Runner 则复用外部平台生态</li></ul>`,23)])])}const g=a(s,[["render",d]]);export{c as __pageData,g as default};
